import base64
import binascii
from PIL import Image
import io

# Stringa base64 (assicurati che sia pulita)
b64_string = "" # (Tua stringa)

def decode_base64(data):
    # Rimuove intestazione se presente
    if "," in data:
        data = data.split(",")[1]
    # Sistema il padding
    missing_padding = len(data) % 4
    if missing_padding:
        data += '=' * (4 - missing_padding)
    return base64.b64decode(data)

try:
    img_data = decode_base64(b64_string)
    img = Image.open(io.BytesIO(img_data)).convert('RGBA')
    
    # Ridimensiona per rendere i pixel gestibili (es. larghezza 120 pixel)
    w_size = 120
    h_size = int((w_size / img.size[0]) * img.size[1])
    img = img.resize((w_size, h_size), Image.NEAREST)
    
    pix = img.load()
    width, height = img.size

    # Creiamo il file HTML con coordinate incorporate
    with open("diagramma_automatizzato.html", "w") as f:
        f.write('<style>.grid{display:grid; grid-template-columns:repeat('+str(width)+', 6px); background:#f0f0f0; gap:0;}')
        f.write('.p{width:6px; height:6px; transition:0.2s;} .active{background:#00FF00 !important; box-shadow:0 0 5px #00FF00;}</style>')
        f.write('<div class="grid">')
        
        for y in range(height):
            for x in range(width):
                r, g, b, a = pix[x, y]
                # Se il pixel non è bianco, è parte del diagramma
                is_part = "p" if (r < 230 or g < 230 or b < 230) else "e"
                color = f"rgba({r},{g},{b},{a})" if is_part == "p" else "transparent"
                f.write(f'<div id="px-{x}-{y}" class="{is_part}" data-x="{x}" data-y="{y}" style="background:{color}"></div>')
        
        f.write('</div>')
    print("Mappatura completata: apri diagramma_automatizzato.html")

except Exception as e:
    print(f"Errore: {e}")